import React from 'react';

export default function Games() {
  const games = [
      { title: 'Mystic Quest', genre: 'Adventure', color: 'yellow', animal: 'Cats!!' },
      { title: 'Space Racer', genre: 'Racing', color: 'green',animal:'Lion!!' },
      { title: 'Space Racer', genre: 'Racing', color: 'green',animal:'Lion!!' },
      { title: 'Space Racer', genre: 'Racing', color: 'green',animal:'Lion!!' },
      { title: 'Space Racer', genre: 'Racing', color: 'green',animal:'Lion!!' },
      { title: 'Space Racer', genre: 'Racing', color: 'green',animal:'Lion!!' },
      { title: 'Space Racer', genre: 'Racing', color: 'green',animal:'Lion!!' },
      { title: 'Space Racer', genre: 'Racing', color: 'green',animal:'Lion!!' },
      { title: 'Space Racer', genre: 'Racing', color: 'green',animal:'Lion!!' },
  ];

  return (
    <main>
      <h1>Browse Our Selection</h1>
      <section>
        {
            games.map(game => (
                        <GameCard title={game.title} genre={game.genre} color={game.color} animal={game.animal} />
                    )
                )
        }
      </section>
    </main>
  );
}

function GameCard({ title='a', genre='b', color='c', animal='d' }) {
  return (
    <article className="game-card">
      <h2>{title}</h2>
      <p>{genre}</p>
      <p>{color}</p>
      <p>{animal}</p>
    </article>
  );
}
